class FixedWindowRateLimiter:
    def __init__(self, limit: int, window_seconds: int):
        self.limit = limit
        self.window = window_seconds
        self.counters: dict[str, int] = {}

    def is_allowed(self, key: str) -> bool:
        import time
        now = int(time.time())
        window_start = now - (now % self.window)
        counter_key = f"{key}:{window_start}"
        count = self.counters.get(counter_key, 0)
        if count >= self.limit:
            return False
        self.counters[counter_key] = count + 1
        return True

class TokenBucketRateLimiter:
    def __init__(self, bucket_size: int, refill_rate: float):
        self.bucket_size = bucket_size
        self.refill_rate = refill_rate  # tokens per second
        self.buckets: dict = {}

    def is_allowed(self, key: str, tokens: int = 1) -> bool:
        import time
        now = time.time()
        bucket = self.buckets.get(key, {
            "tokens": self.bucket_size, "last_refill": now
        })
        elapsed = now - bucket["last_refill"]
        bucket["tokens"] = min(
            self.bucket_size,
            bucket["tokens"] + elapsed * self.refill_rate
        )
        bucket["last_refill"] = now
        if bucket["tokens"] >= tokens:
            bucket["tokens"] -= tokens
            self.buckets[key] = bucket
            return True
        return False
